{
  "grammar": [
    {
      "pattern": "本來 + 想/要 + verb + 可是/但是 + 後來 + verb + 結果",
      "structure": ["本來", "想/要", "verb", "可是/但是", "後來", "verb", "結果"],
      "explanation_en": "Use '本來' to state an original plan or intention, then use '可是/但是' to introduce a change, '後來' to describe what happened next, and '結果' to give the final outcome. This structure is common in storytelling to show contrast between expectation and reality.",
      "title": "本來...後來...結果",
      "meaning": "Originally... but later... as a result",
      "when_to_use": [
        "When telling a story about a plan that changed",
        "When explaining why something unexpected happened",
        "When contrasting an original intention with the actual outcome"
      ],
      "when_not_to_use": [
        "Do not use for simple sequential events without contrast",
        "Do not use when the original plan and outcome are the same"
      ],
      "pragmatic_notes": "In Taiwan, this pattern is very common in casual conversation when sharing personal anecdotes. It adds a dramatic or surprising element to the story. Often used with a pause or tone change to emphasize the twist.",
      "word_order_notes": "The order is fixed: 本來 comes first, then the original plan, then 可是/但是, then 後來, then the new action, then 結果 for the outcome.",
      "english_contrast": "English might use 'I was going to... but then... so...' or 'Originally... however... in the end...'",
      "korean_contrast": "Korean might use '원래 ...려고 했는데 그런데 나중에 ... 결국 ...'",
      "negative_examples": [
        {
          "text": "我本來想喝咖啡，可是後來喝咖啡。",
          "error": "The outcome is the same as the original plan, so no contrast is needed. Use 結果 only when there is a change."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我本來想喝咖啡，可是後來喝咖啡。",
          "error": "The outcome is the same as the original plan, so no contrast is needed. Use 結果 only when there is a change."
        }
      ],
      "transformation_drills": [
        "Change: 我本來想喝咖啡，可是後來我喝茶。 → 我本來想喝咖啡，可是後來我喝茶，結果我覺得很開心。"
      ],
      "production_drills": [
        "Tell a story: 你本來想去公園，可是後來去商店，結果買了東西。"
      ],
      "common_error_patterns": [
        "Using 結果 when there is no change or outcome",
        "Forgetting 可是/但是 before 後來"
      ],
      "repair_feedback": {
        "word_order": "Make sure 本來 comes first, then the original plan, then 可是/但是, then 後來, then the new action, then 結果.",
        "politeness": "This pattern is neutral and can be used in both casual and formal storytelling.",
        "vocabulary": "Use verbs like 想, 要, 打算 after 本來."
      }
    },
    {
      "pattern": "因為 + event + 所以 + result/feeling",
      "structure": ["因為", "event", "所以", "result/feeling"],
      "explanation_en": "Use '因為...所以...' to express cause and effect. The first part states the reason, and the second part states the result or feeling. This is a basic but essential structure for storytelling to explain why things happened.",
      "title": "因為...所以...",
      "meaning": "Because... so...",
      "when_to_use": [
        "When explaining the reason for an event in a story",
        "When connecting a cause to an emotional reaction",
        "When giving a logical explanation in a narrative"
      ],
      "when_not_to_use": [
        "Do not use when the relationship is not causal",
        "Do not use for simple sequential events without cause-effect"
      ],
      "pragmatic_notes": "In Taiwan, this structure is used very frequently in both spoken and written Chinese. In storytelling, it helps the listener understand why the character felt or acted a certain way. Often the 所以 part can be omitted in casual speech if the result is obvious.",
      "word_order_notes": "The order is fixed: 因為 comes first, then the reason, then 所以, then the result. Both parts are complete clauses.",
      "english_contrast": "English uses 'because... so...' but often omits 'so' in casual speech. Chinese requires both 因為 and 所以 in formal writing, but in speech 所以 can be dropped.",
      "korean_contrast": "Korean uses '...기 때문에 ...해서' or '...아/어서 ...'",
      "negative_examples": [
        {
          "text": "因為我早上出門，所以我回家。",
          "error": "There is no clear cause-effect relationship between going out and coming home. Use 因為...所以 only when the second event is a direct result of the first."
        }
      ],
      "incorrect_examples": [
        {
          "text": "因為我早上出門，所以我回家。",
          "error": "There is no clear cause-effect relationship between going out and coming home. Use 因為...所以 only when the second event is a direct result of the first."
        }
      ],
      "transformation_drills": [
        "Change: 我早上出門，我遇到朋友。 → 因為我早上出門，所以我遇到朋友。"
      ],
      "production_drills": [
        "Tell a story: 因為你忘記帶鑰匙，所以你進不了家門。"
      ],
      "common_error_patterns": [
        "Using 因為...所以 for unrelated events",
        "Omitting 所以 in formal writing"
      ],
      "repair_feedback": {
        "word_order": "Place 因為 before the reason and 所以 before the result.",
        "politeness": "This structure is neutral and appropriate for all contexts.",
        "vocabulary": "Use complete clauses after both 因為 and 所以."
      }
    },
    {
      "pattern": "verb + 了 + 以後 + 覺得 + feeling/emotion",
      "structure": ["verb", "了", "以後", "覺得", "feeling/emotion"],
      "explanation_en": "Use 'verb + 了 + 以後 + 覺得' to describe how you felt after doing something. This structure is very useful in storytelling to express emotional reactions to events. The 了 indicates completion of the action.",
      "title": "verb + 了 + 以後 + 覺得",
      "meaning": "After doing something, I feel...",
      "when_to_use": [
        "When describing emotional reactions after an event",
        "When telling a story about personal experiences",
        "When explaining how an event affected your mood"
      ],
      "when_not_to_use": [
        "Do not use for habitual actions (use 的時候 instead)",
        "Do not use when the feeling is not directly after the action"
      ],
      "pragmatic_notes": "In Taiwan, this pattern is very common in casual storytelling. It helps the listener understand the emotional impact of events. Often used with emotions like 開心, 難過, 生氣, 緊張, 害怕.",
      "word_order_notes": "The verb must be followed by 了 to show completion, then 以後, then 覺得, then the emotion. The subject is usually at the beginning.",
      "english_contrast": "English uses 'After I did..., I felt...' or 'Having done..., I felt...'",
      "korean_contrast": "Korean uses '...고 나서 ...라고 느꼈다' or '...한 후에 ...라고 느꼈다'",
      "negative_examples": [
        {
          "text": "我喝咖啡以後覺得開心。",
          "error": "Missing 了 after the verb. For a completed action, you need 了 to indicate the action is finished."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我喝咖啡以後覺得開心。",
          "error": "Missing 了 after the verb. For a completed action, you need 了 to indicate the action is finished."
        }
      ],
      "transformation_drills": [
        "Change: 我遇到朋友，我覺得開心。 → 我遇到朋友了以後，我覺得開心。"
      ],
      "production_drills": [
        "Tell a story: 你回家以後覺得很累。"
      ],
      "common_error_patterns": [
        "Omitting 了 after the verb",
        "Using 以後 for simultaneous actions"
      ],
      "repair_feedback": {
        "word_order": "Place 了 immediately after the verb, then 以後, then 覺得, then the emotion.",
        "politeness": "This structure is neutral and suitable for all contexts.",
        "vocabulary": "Use emotion words like 開心, 難過, 生氣, 緊張, 害怕, 舒服, 累."
      }
    }
  ]
}
